query:
{
  cloudSqlInstances(
    where: {
      cyscaleEngineIsOutdated: { eq: true }
      NOT: {
        OR: [
          { engine: { eq: "mysql" }, engineVersion_MATCHES: "^5\\.7(\\.|$)" }
          { engine: { eq: "mysql" }, engineVersion_MATCHES: "^8\\.0(\\.|$)" }
          { engine: { eq: "mysql" }, engineVersion_MATCHES: "^8\\.4(\\.|$)" }
          { engine: { eq: "postgres" }, engineVersion_MATCHES: "^12(\\.|$)" }
          { engine: { eq: "postgres" }, engineVersion_MATCHES: "^13(\\.|$)" }
          { engine: { eq: "postgres" }, engineVersion_MATCHES: "^14(\\.|$)" }
          { engine: { eq: "postgres" }, engineVersion_MATCHES: "^15(\\.|$)" }
          { engine: { eq: "postgres" }, engineVersion_MATCHES: "^16(\\.|$)" }
          { engine: { eq: "postgres" }, engineVersion_MATCHES: "^17(\\.|$)" }
          { engine: { eq: "postgres" }, engineVersion_MATCHES: "^18(\\.|$)" }
          { engine: { eq: "postgresql" }, engineVersion_MATCHES: "^12(\\.|$)" }
          { engine: { eq: "postgresql" }, engineVersion_MATCHES: "^13(\\.|$)" }
          { engine: { eq: "postgresql" }, engineVersion_MATCHES: "^14(\\.|$)" }
          { engine: { eq: "postgresql" }, engineVersion_MATCHES: "^15(\\.|$)" }
          { engine: { eq: "postgresql" }, engineVersion_MATCHES: "^16(\\.|$)" }
          { engine: { eq: "postgresql" }, engineVersion_MATCHES: "^17(\\.|$)" }
          { engine: { eq: "postgresql" }, engineVersion_MATCHES: "^18(\\.|$)" }
        ]
      }
    }
  ) {
    ...AssetFragment
    engine
    engineVersion
    cyscaleEngineIsOutdated
  }
}
